data.syntax:
classDiagram
    class Paper {
        +String title
        +String abstract
        +String doi
        +submit()
        +revise()
    }
    class Author {
        +String name
        +String affiliation
        +String orcid
    }
    class Reference {
        +String citation
        +int year
    }
    class Journal {
        +String name
        +float impactFactor
    }
    class ReviewStatus {
        <<enumeration>>
        SUBMITTED
        UNDER_REVIEW
        ACCEPTED
        REJECTED
    }
    Paper "1" --> "*" Author : authors
    Paper "1" --> "*" Reference : references
    Paper "*" --> "1" Journal : publishedIn
    Paper --> ReviewStatus : status
